.address-table {
    width: 100%;
    table-layout: fixed;   /* ⭐ VERY IMPORTANT */
    border-spacing: 0;
    margin: 8px 15px 0 15px;
    font-size: 14px;
}

.addr-head {
    padding: 8px;
    font-weight: bold;
    border: 1px solid #999;
}

.addr-body {
    padding: 8px;
    vertical-align: top;
    border: 1px solid #999;
    word-wrap: break-word;
}
